customCSS:
/*make bg transparent*/
/* html[dark], html, body, #container.ytd-searchbox, ytd-app, #page-header-container, #page-header, #tabs-container, #tabs-inner-container, #chips-wrapper, .navigation-container, #cinematic-shorts-scrim, #shorts-container, .ytLrGuideResponseMask, .ytLrPromoShelfRendererContainer, ytd-item-section-renderer[page-subtype="playlist"] #header.ytd-item-section-renderer, .ytd-engagement-panel-title-header-renderer, .ytd-engagement-panel-section-list-renderer {
  background-color: #00000000 !important;
  background: none !important;
}
body::-webkit-scrollbar, ytd-guide-signin-promo-renderer {
  display: none;
  scrollbar-width: none;
}
#tabs-divider, #short-video-container #cinematic-container, #frosted-glass {
  display: none !important;
}
#shorts-container {
  height: 98vh !important;
}
tp-yt-app-drawer > #contentContainer, #guide-content, ytd-mini-guide-renderer, ytd-mini-guide-entry-renderer {
  background-color: #00000000 !important;
  background: none !important;
}
.ytLrPromoShelfRendererPreviewBackground {
  -webkit-mask-image: radial-gradient(circle, rgba(0, 0, 0, 1) 0%, rgba(0, 0, 0, 0) 60%) !important;
  mask-image: radial-gradient(circle, rgba(0, 0, 0, 1) 0%, rgba(0, 0, 0, 0) 50%) !important;
  -webkit-mask-repeat: no-repeat !important;
  mask-repeat: no-repeat !important;
  -webkit-mask-size: cover !important;
  mask-size: cover !important;
} */
/*end*/
/*remove side guide*/
ytd-mini-guide-renderer, [theater=""] #contentContainer::after {
  display: none !important;
}
tp-yt-app-drawer > #contentContainer:not([opened=""]), #contentContainer:not([opened=""]) #guide-content, ytd-mini-guide-renderer, ytd-mini-guide-entry-renderer {
  background-color: var(--yt-spec-text-primary-inverse) !important;
  background: var(--yt-spec-text-primary-inverse) !important;
}
#content:not(:has(#contentContainer[opened=""])) #page-manager {
  margin-left: 0 !important;
}
ytd-app:not([guide-persistent-and-visible=""]) tp-yt-app-drawer > #contentContainer {
  background-color: var(--yt-spec-text-primary-inverse) !important;
}
ytd-alert-with-button-renderer {
  align-items: center !important;
  justify-content: center !important;
}
/*end*/
/*compact feed*/
ytd-rich-item-renderer {
  margin-bottom: 15px !important;
  [rendered-from-rich-grid] {
    --ytd-rich-item-row-usable-width: calc(100% - var(--ytd-rich-grid-gutter-margin) * 1) !important;
  }

  #metadata.ytd-video-meta-block {
    flex-direction: row !important;

    #metadata-line span:nth-child(3) {
      height: 1em !important;
      margin-left: 1em !important;
    }
  }
}
ytd-rich-grid-media {
  border-radius: 1.2em;
  height: 100% !important;

  ytd-menu-renderer #button {
    opacity: 0 !important;
    transition: opacity 0.3s ease-in-out !important;
  }
  :hover ytd-menu-renderer #button {
    opacity: 1 !important;
  }
}
/*end*/
/*theatre mode is pseudo full screen*/
#content:has(ytd-masthead[theater=""]) #full-bleed-container {
  height: 100vh !important;
  max-height: 100vh !important;
  top: 0 !important;
}
#masthead-container, #columns #secondary {
  transition: all 0.3s ease-in-out 0.5s !important;
}
body:has([fullscreen=""], [theater=""]):not(:has(ytd-watch-flexy[hidden=""])) #masthead-container:not(:has(.ytSearchboxComponentInputBoxHasFocus)) {
  top: -40px !important;
  opacity: 0 !important;
  transition: all 0.3s cubic-bezier(0.445, 0.05, 0.55, 0.95) !important;
  &:hover {
    opacity: 1 !important;
    top: 0 !important;
  }
}
ytd-app:has([fullscreen=""], [theater=""]):not(:has(ytd-watch-flexy[hidden=""])) {
  --ytd-toolbar-height: 0px !important;

  #page-manager {
    margin: 0 !important;
  }
}
/*end*/
/*fix only 3 columns of video in feed*/
ytd-rich-item-renderer[rendered-from-rich-grid] {
  @media only screen and (min-width: 1400px) {
    --ytd-rich-grid-items-per-row: 4 !important;

    @media only screen and (min-width: 1700px) {
      --ytd-rich-grid-items-per-row: 5 !important;

      @media only screen and (min-width: 2180px) {
        --ytd-rich-grid-items-per-row: 6 !important;
      }
    }
  }
}
ytd-rich-item-renderer[is-in-first-column=""] {
  margin-left: calc(var(--ytd-rich-grid-item-margin) / 2) !important;
}
#contents {
  padding-left: calc(var(--ytd-rich-grid-item-margin) / 2 + var(--ytd-rich-grid-gutter-margin)) !important;
}
/*end*/
/*new to you chip*/
#chips {
  display: flex !important;
}
#chips > yt-chip-cloud-chip-renderer:nth-last-child(1) {
  order: 1 !important;
  margin-right: 12px !important;
}
#chips > yt-chip-cloud-chip-renderer:not(:nth-last-child(1)) {
  order: 2 !important;
}
#chips > yt-chip-cloud-chip-renderer:nth-child(1) {
  order: 1 !important;
}
/*end*/
